codeExercises.solution:
import React from 'react';
import theme from './theme';
import { ThemeProvider, CssBaseline } from '@mui/material';
import Box from '@mui/material/Box';

function App() {
  return (
    <ThemeProvider theme={theme}>
      <CssBaseline />
      <Box>Hello World!</Box>
    </ThemeProvider>
  );
}

export default App;

