codeExercises.solution:
import { createTheme } from '@mui/material/styles';

const theme = createTheme({
  palette: {
    primary: {
      main: '#1565c0', // Một màu xanh đậm hơn
    },
  },
  components: {
    MuiAppBar: {
      styleOverrides: {
        root: ({ theme }) => ({
          backgroundColor: '#ffffff',
          color: theme.palette.primary.main
        })
      }
    }
  }
});

export default theme;
